import json
import boto3
import logging
from datetime import datetime
from botocore.exceptions import ClientError

logger = logging.getLogger()
logger.setLevel(logging.INFO)

sns_client = boto3.client('sns')

NOTIFICATION_TYPES = {
    'alert': {
        'subject_prefix': '[ALERT]',
        'default_priority': 'high',
        'message_attributes': {
            'priority': {'DataType': 'String', 'StringValue': 'high'},
            'category': {'DataType': 'String', 'StringValue': 'alert'}
        }
    },
    'info': {
        'subject_prefix': '[INFO]',
        'default_priority': 'low',
        'message_attributes': {
            'priority': {'DataType': 'String', 'StringValue': 'low'},
            'category': {'DataType': 'String', 'StringValue': 'informational'}
        }
    },
    'warning': {
        'subject_prefix': '[WARNING]',
        'default_priority': 'medium',
        'message_attributes': {
            'priority': {'DataType': 'String', 'StringValue': 'medium'},
            'category': {'DataType': 'String', 'StringValue': 'warning'}
        }
    },
    'critical': {
        'subject_prefix': '[CRITICAL]',
        'default_priority': 'critical',
        'message_attributes': {
            'priority': {'DataType': 'String', 'StringValue': 'critical'},
            'category': {'DataType': 'String', 'StringValue': 'critical'}
        }
    },
    'transactional': {
        'subject_prefix': '[TRANSACTION]',
        'default_priority': 'medium',
        'message_attributes': {
            'priority': {'DataType': 'String', 'StringValue': 'medium'},
            'category': {'DataType': 'String', 'StringValue': 'transactional'}
        }
    }
}


def validate_event(event):
    required_fields = ['topic_arn', 'message', 'notification_type']
    missing_fields = [field for field in required_fields if field not in event]
    if missing_fields:
        raise ValueError(f"Missing required fields: {', '.join(missing_fields)}")

    notification_type = event['notification_type']
    if notification_type not in NOTIFICATION_TYPES:
        raise ValueError(
            f"Invalid notification_type '{notification_type}'. "
            f"Must be one of: {', '.join(NOTIFICATION_TYPES.keys())}"
        )

    topic_arn = event['topic_arn']
    if not topic_arn.startswith('arn:aws:sns:'):
        raise ValueError(f"Invalid topic ARN format: {topic_arn}")

    return True


def build_message(event):
    notification_type = event['notification_type']
    type_config = NOTIFICATION_TYPES[notification_type]
    message_body = event['message']
    subject = event.get('subject', 'Event Notification')
    full_subject = f"{type_config['subject_prefix']} {subject}"

    # Truncate subject to SNS limit of 100 characters
    if len(full_subject) > 100:
        full_subject = full_subject[:97] + '...'

    timestamp = datetime.utcnow().isoformat() + 'Z'

    structured_message = {
        'notification_type': notification_type,
        'priority': type_config['default_priority'],
        'timestamp': timestamp,
        'subject': full_subject,
        'message': message_body,
        'source': event.get('source', 'event-notification-system'),
        'metadata': event.get('metadata', {})
    }

    # Build message attributes, merging defaults with any custom ones
    message_attributes = dict(type_config['message_attributes'])
    custom_attributes = event.get('message_attributes', {})
    for key, value in custom_attributes.items():
        if isinstance(value, str):
            message_attributes[key] = {
                'DataType': 'String',
                'StringValue': value
            }
        elif isinstance(value, dict) and 'DataType' in value and ('StringValue' in value or 'BinaryValue' in value):
            message_attributes[key] = value

    # Add timestamp attribute
    message_attributes['timestamp'] = {
        'DataType': 'String',
        'StringValue': timestamp
    }

    return structured_message, full_subject, message_attributes


def publish_standard_message(topic_arn, structured_message, subject, message_attributes):
    response = sns_client.publish(
        TopicArn=topic_arn,
        Message=json.dumps(structured_message, default=str),
        Subject=subject,
        MessageAttributes=message_attributes
    )
    return response


def publish_multi_protocol_message(topic_arn, structured_message, subject, message_attributes):
    plain_text_message = (
        f"{subject}\n"
        f"{'=' * len(subject)}\n\n"
        f"Type: {structured_message['notification_type']}\n"
        f"Priority: {structured_message['priority']}\n"
        f"Time: {structured_message['timestamp']}\n"
        f"Source: {structured_message['source']}\n\n"
        f"Message:\n{structured_message['message']}\n"
    )

    multi_protocol_message = {
        'default': json.dumps(structured_message, default=str),
        'email': plain_text_message,
        'sms': f"{subject}: {structured_message['message']}"[:160],
        'lambda': json.dumps(structured_message, default=str),
        'sqs': json.dumps(structured_message, default=str),
        'http': json.dumps(structured_message, default=str),
        'https': json.dumps(structured_message, default=str)
    }

    response = sns_client.publish(
        TopicArn=topic_arn,
        Message=json.dumps(multi_protocol_message, default=str),
        Subject=subject,
        MessageStructure='json',
        MessageAttributes=message_attributes
    )
    return response


def publish_batch_messages(messages):
    results = {
        'successful': [],
        'failed': []
    }

    for idx, msg_event in enumerate(messages):
        try:
            validate_event(msg_event)
            structured_message, subject, message_attributes = build_message(msg_event)

            use_multi_protocol = msg_event.get('multi_protocol', False)

            if use_multi_protocol:
                response = publish_multi_protocol_message(
                    msg_event['topic_arn'], structured_message, subject, message_attributes
                )
            else:
                response = publish_standard_message(
                    msg_event['topic_arn'], structured_message, subject, message_attributes
                )

            results['successful'].append({
                'index': idx,
                'message_id': response['MessageId'],
                'topic_arn': msg_event['topic_arn'],
                'notification_type': msg_event['notification_type']
            })

        except (ValueError, ClientError) as e:
            logger.error(f"Failed to publish message at index {idx}: {str(e)}")
            results['failed'].append({
                'index': idx,
                'error': str(e),
                'topic_arn': msg_event.get('topic_arn', 'unknown')
            })

    return results


def lambda_handler(event, context):
    logger.info(f"Received event: {json.dumps(event, default=str)}")

    try:
        # Check if this is a batch request
        if 'messages' in event and isinstance(event['messages'], list):
            logger.info(f"Processing batch of {len(event['messages'])} messages")
            batch_results = publish_batch_messages(event['messages'])

            success_count = len(batch_results['successful'])
            fail_count = len(batch_results['failed'])

            return {
                'statusCode': 200 if fail_count == 0 else 207,
                'body': {
                    'batch_result': True,
                    'total_messages': len(event['messages']),
                    'successful_count': success_count,
                    'failed_count': fail_count,
                    'results': batch_results
                }
            }

        # Single message processing
        validate_event(event)

        structured_message, subject, message_attributes = build_message(event)
        topic_arn = event['topic_arn']
        use_multi_protocol = event.get('multi_protocol', False)

        logger.info(
            f"Publishing {event['notification_type']} notification to {topic_arn} "
            f"(multi_protocol={use_multi_protocol})"
        )

        if use_multi_protocol:
            response = publish_multi_protocol_message(
                topic_arn, structured_message, subject, message_attributes
            )
        else:
            response = publish_standard_message(
                topic_arn, structured_message, subject, message_attributes
            )

        logger.info(f"Message published successfully. MessageId: {response['MessageId']}")

        return {
            'statusCode': 200,
            'body': {
                'message_id': response['MessageId'],
                'topic_arn': topic_arn,
                'notification_type': event['notification_type'],
                'subject': subject,
                'timestamp': structured_message['timestamp'],
                'multi_protocol': use_multi_protocol,
                'status': 'published'
            }
        }

    except ValueError as e:
        logger.error(f"Validation error: {str(e)}")
        return {
            'statusCode': 400,
            'body': {
                'error': 'ValidationError',
                'message': str(e)
            }
        }

    except ClientError as e:
        error_code = e.response['Error']['Code']
        error_message = e.response['Error']['Message']
        logger.error(f"AWS SNS error: {error_code} - {error_message}")
        return {
            'statusCode': 500,
            'body': {
                'error': error_code,
                'message': error_message
            }
        }

    except Exception as e:
        logger.error(f"Unexpected error: {str(e)}", exc_info=True)
        return {
            'statusCode': 500,
            'body': {
                'error': 'InternalError',
                'message': str(e)
            }
        }


